import{_ as e,o as t,c as s,a2 as n}from"./chunks/framework.DGp-bpT-.js";const g=JSON.parse('{"title":"Форматирование алертов","description":"","frontmatter":{},"headers":[],"relativePath":"guide/alert-formatting.md","filePath":"guide/alert-formatting.md","lastUpdated":1775043628000}'),l={name:"guide/alert-formatting.md"};function r(o,a,p,i,d,c){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="форматирование-алертов" tabindex="-1">Форматирование алертов <a class="header-anchor" href="#форматирование-алертов" aria-label="Permalink to &quot;Форматирование алертов&quot;">​</a></h1><p>Для того чтобы SREBot быстро и надежно распознавал ваши уведомления без лишних затрат на нейросеть, рекомендуется следовать определенным стандартам при настройке шаблонов в Alertmanager.</p><p>Бот поддерживает <strong>гибридный парсинг</strong>: сначала пробует быстрые регулярные выражения (локально), а если они не срабатывают — использует интеллектуальный парсинг через LLM (на бекенде).</p><hr><h2 id="🚀-рекомендуемые-шаблоны" tabindex="-1">🚀 Рекомендуемые шаблоны <a class="header-anchor" href="#🚀-рекомендуемые-шаблоны" aria-label="Permalink to &quot;🚀 Рекомендуемые шаблоны&quot;">​</a></h2><h3 id="_1-стандартныи-самыи-быстрыи" tabindex="-1">1. Стандартный (самый быстрый) <a class="header-anchor" href="#_1-стандартныи-самыи-быстрыи" aria-label="Permalink to &quot;1. Стандартный (самый быстрый)&quot;">​</a></h3><p>Этот формат лучше всего подходит для больших объемов данных, так как обрабатывается мгновенно простыми регулярками.</p><p><strong>Пример:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🚨 Alerts Firing:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Labels:</span></span>
<span class="line"><span> - alertname = CPUUsageHigh</span></span>
<span class="line"><span> - cluster = yandex-production</span></span>
<span class="line"><span> - severity = critical</span></span>
<span class="line"><span> - namespace = default</span></span>
<span class="line"><span>Annotations:</span></span>
<span class="line"><span> - summary = CPU usage is above 90%</span></span>
<span class="line"><span>Source: http://prometheus/graph</span></span></code></pre></div><h3 id="_2-markdown-bold-для-slack-telegram" tabindex="-1">2. Markdown/Bold (для Slack/Telegram) <a class="header-anchor" href="#_2-markdown-bold-для-slack-telegram" aria-label="Permalink to &quot;2. Markdown/Bold (для Slack/Telegram)&quot;">​</a></h3><p>Если вы используете жирный шрифт для ключей, бот поймет и такой формат.</p><p><strong>Пример:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔥 [FIRING:1] KubePodNotReady</span></span>
<span class="line"><span>*Alert:* Pod has been non-ready for more than 15 minutes.</span></span>
<span class="line"><span>*Details:*</span></span>
<span class="line"><span> • *alertname:* \`KubePodNotReady\`</span></span>
<span class="line"><span> • *cluster:* \`yandex-production\`</span></span>
<span class="line"><span> • *namespace:* \`canton\`</span></span>
<span class="line"><span> • *severity:* \`warning\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>*Annotations:*</span></span>
<span class="line"><span> • *summary:* Pod validator-app is failing</span></span>
<span class="line"><span>Source: http://alertmanager/details</span></span></code></pre></div><hr><h2 id="🔍-обязательные-поля" tabindex="-1">🔍 Обязательные поля <a class="header-anchor" href="#🔍-обязательные-поля" aria-label="Permalink to &quot;🔍 Обязательные поля&quot;">​</a></h2><p>Для корректной работы анализа боту критически важны следующие метки (labels):</p><table tabindex="0"><thead><tr><th style="text-align:left;">Метка</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>alertname</code></td><td style="text-align:left;">Идентификатор проблемы (по нему ищется история).</td></tr><tr><td style="text-align:left;"><code>cluster</code></td><td style="text-align:left;">Название кластера. Должно совпадать с ключом в <code>config.yml</code> для работы инструментов (Prometheus/Elastic).</td></tr><tr><td style="text-align:left;"><code>severity</code></td><td style="text-align:left;">Важность (critical, warning, info).</td></tr><tr><td style="text-align:left;"><code>namespace</code></td><td style="text-align:left;">(Желательно) Помогает сузить поиск логов и метрик до конкретного окружения.</td></tr></tbody></table><hr><h2 id="🛠-умныи-парсинг-smart-fallback" tabindex="-1">🛠 Умный парсинг (Smart Fallback) <a class="header-anchor" href="#🛠-умныи-парсинг-smart-fallback" aria-label="Permalink to &quot;🛠 Умный парсинг (Smart Fallback)&quot;">​</a></h2><p>Если ваш шаблон сильно отличается от стандартных (например, вы присылаете просто текст «У нас упал прод в кластере X»), бот отправит это сообщение на <strong>интеллектуальный парсинг</strong> на бекенд.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Интеллектуальный парсинг тратит токены вашей организации и логируется на бекенде. Мы рекомендуем использовать стандартные шаблоны для автоматических алертов и оставлять Smart-режим для внештатных ситуаций или ручных сообщений.</p></div><hr><h2 id="💡-советы-по-настроике" tabindex="-1">💡 Советы по настройке <a class="header-anchor" href="#💡-советы-по-настроике" aria-label="Permalink to &quot;💡 Советы по настройке&quot;">​</a></h2><ol><li><strong>Используйте <code>cluster</code></strong>: Всегда добавляйте метку <code>cluster</code>. Если бот не найдет в алерте кластер, он не сможет вызвать инструменты диагностики (MCP), так как не будет знать, к какому Prometheus обращаться.</li><li><strong>Разделяйте Firing и Resolved</strong>: Используйте четкие заголовки (или эмодзи 🚨/🔥 для Firing и ✅ для Resolved) в начале сообщения.</li><li><strong>Source URL</strong>: Ссылка <code>Source:</code> в конце сообщения позволяет боту (и вам) быстро перейти в интерфейс Alertmanager/Prometheus.</li></ol>`,24)])])}const m=e(l,[["render",r]]);export{g as __pageData,m as default};
